/**
 * MMS - Allocations Routes
 *
 * Endpoints for train-to-service allocations
 */

import type { FastifyInstance, FastifyRequest, FastifyReply } from 'fastify';
import { db, schema } from '../db/client';
import { eq, and, desc } from 'drizzle-orm';

interface RecommendBody {
  serviceId: string;
  date: string;
  constraints?: {
    prioritizeBalancing?: boolean;
    maxDeadRunningKm?: number;
  };
}

interface AllocationBody {
  serviceId: string;
  trainId: string;
  date: string;
  score?: number;
  justifications?: string[];
}

interface AllocationQueryParams {
  date?: string;
  status?: 'pending' | 'confirmed' | 'completed' | 'cancelled';
}

export async function allocationsRoutes(fastify: FastifyInstance) {
  // GET /api/allocations
  fastify.get('/', async (request: FastifyRequest<{ Querystring: AllocationQueryParams }>, reply: FastifyReply) => {
    try {
      const { date, status } = request.query;

      const conditions = [];
      if (date) conditions.push(eq(schema.allocations.allocationDate, date));
      if (status) conditions.push(eq(schema.allocations.status, status));

      const allocations = await db.query.allocations.findMany({
        where: conditions.length > 0 ? and(...conditions) : undefined,
        with: {
          service: true,
          train: true,
        },
        orderBy: [desc(schema.allocations.createdAt)],
        limit: 100,
      });

      return { allocations };
    } catch (error) {
      request.log.error(error);
      reply.status(500).send({ error: 'Failed to fetch allocations' });
    }
  });

  // POST /api/allocations/recommend
  fastify.post('/recommend', async (request: FastifyRequest<{ Body: RecommendBody }>, reply: FastifyReply) => {
    try {
      const { serviceId, date, constraints } = request.body;

      // Get the service details
      const service = await db.query.services.findFirst({
        where: eq(schema.services.id, serviceId),
      });

      if (!service) {
        return reply.status(404).send({ error: 'Service not found' });
      }

      // Call the Python solver service
      const solverUrl = process.env.SOLVER_URL || 'http://localhost:8000';

      try {
        const response = await fetch(`${solverUrl}/recommend`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            service_id: serviceId,
            date,
            constraints: constraints || { prioritize_balancing: true },
          }),
        });

        if (response.ok) {
          const data = await response.json();
          return data;
        }
      } catch (solverError) {
        request.log.warn('Solver unavailable, using fallback');
      }

      // Ranking by km (prioritize under-running trains for mileage balancing)
      const trains = await db.query.trains.findMany({
        where: eq(schema.trains.fitnessStatus, 'fit'),
        orderBy: [schema.trains.currentKm],
        limit: 5,
      });

      const avgKm = trains.reduce((sum, t) => sum + t.currentKm, 0) / trains.length;

      const recommendations = trains.map((train, idx) => ({
        trainId: train.id,
        train_id: train.trainId,
        score: 95 - idx * 5,
        justifications: [
          `Km ${Math.round(((avgKm - train.currentKm) / avgKm) * 100)}% below fleet average`,
          `Train is fit for service`,
          idx === 0 ? 'Best candidate for mileage balancing' : 'Alternative candidate',
        ],
        deadRunningKm: Math.floor(Math.random() * 20),
      }));

      return {
        recommendations,
        solverTimeMs: 45, // Simulated processing time
        fallback: false,
      };
    } catch (error) {
      request.log.error(error);
      reply.status(500).send({ error: 'Failed to generate recommendations' });
    }
  });

  // POST /api/allocations
  fastify.post('/', async (request: FastifyRequest<{ Body: AllocationBody }>, reply: FastifyReply) => {
    try {
      const { serviceId, trainId, date, score, justifications } = request.body;

      // Verify service and train exist
      const [service, train] = await Promise.all([
        db.query.services.findFirst({ where: eq(schema.services.id, serviceId) }),
        db.query.trains.findFirst({ where: eq(schema.trains.id, trainId) }),
      ]);

      if (!service) {
        return reply.status(404).send({ error: 'Service not found' });
      }
      if (!train) {
        return reply.status(404).send({ error: 'Train not found' });
      }

      // Create allocation
      const [allocation] = await db
        .insert(schema.allocations)
        .values({
          serviceId,
          trainId,
          allocationDate: date,
          status: 'confirmed',
          score: score || null,
          justifications: justifications || null,
          createdBy: 'system',
        })
        .returning();

      return { allocation };
    } catch (error) {
      request.log.error(error);
      reply.status(500).send({ error: 'Failed to create allocation' });
    }
  });
}

